import Child from './components/Child';

const Example = () => {
  const hello = (arg) => `Hello ${arg}`;
  const o = {
    color: 'red',
    num: 123,
  };
  return (
    <>
      <Child color={o.color} num={123} fn={hello} bool obj={{ name: 'Tom', age: 16 }}></Child>
      {/* <Child color="red"></Child> */}
    </>
  );
};

export default Example;
